import{_ as r}from"./nyalra_kb-7135827b.js";import{_ as c,W as p,X as s,Y as _,Z as e,$ as t,a0 as o,a2 as i,a1 as d,C as a}from"./framework-a4c02b8f.js";const m={},f=e("figure",null,[e("img",{src:r,alt:"",tabindex:"0",loading:"lazy"}),e("figcaption")],-1),h={href:"https://tree-novel.com/works/episode/82710f8ecbf2b03e228ad0a39a5feecc.html",target:"_blank",rel:"noopener noreferrer"},u=e("p",null,"这是在互联网中栖息的不可思议生物·Nyalra于深夜写下的有关互联网、独居生活以及除此之外的事物的图文随笔。",-1),k=d('<hr><p>晚上好，我是にゃるら。</p><p>撰写这篇稿件之时，正是我的拙作『NEEDY GIRL OVERDOSE』Nintendo Switch版即将发售之时，工作人员和粉丝们都非常兴奋。但与互联网上的状况无关，我仍然像往常一样独自在房间里咔嗒咔嗒地敲击着键盘。人生一直都是这样的吧。即使创作者有大型的事件，那也只是在网络上发生的事情，基本上还是坐在家里面对着电脑或手机。这就是现代社会。</p><p>先不管这个，在深夜一个人度过的话，会浮现出讨厌的东西吧。「一人反省会」。在自己最近的言行举止之中，回想起来就会感到羞耻的事情也好，担心是否被误会的事情也好，一个接一个无休止地被联想到。说实话，现在正在敲键盘的我也正处于一人反省会之中，为了逃避它，即使离截稿日期还早，我还是在写稿。这样一来既能逃避，又能得到稿费，一举两得。工作实在是一件让人非常不愉快的事情，但也正因为如此，它能让我方便地忘记一些琐事。嘛，不过大部分的烦恼琐事应该都源于工作吧。</p><p>前几天，当我和责任编辑讨论这个专栏时，他问我：“你看起来挺忙的，连载没问题吗？”我回答说：“如果是1000字左右的专栏，无论什么时候都来得及，所以不用担心！”实际上，我每天都会习惯地在note上发布1000字左右的日记，所以这种程度并不是什么大问题。</p><p>然而，似乎我的说法显得太过于自信，所以被轻蔑地嘲笑了：“那真是值得信赖啊（笑。”确实，回想起来，我说话的语气确实有点傲慢，不必要地表现出了自以为是的意味，我自己都觉得好笑。真是丢脸……</p><p>这种对话从编辑的角度来看无所谓，特意解释“不对，我当时并不是在装……”也很奇怪。而且，在想起来丢脸的时候才在LINE上提起“关于那时的对话……”显得愈发可疑。但是，如果不消除这个误会，我会被一人反省会的羞耻感所压垮吧……！</p><p>经历这件事后，我意识到如果正好在稿件中写下这一系列事情，就能解决所有问题，于是就这样写了。呀，这真是太好了。我真的并不是在装，我只是想用一种能够让人放心的方式回应担心，并赢得信任。我想被别人认为“意外地能够守护好要守护的东西呢”……！为了直截了当地传达这一点，我才那样说了。</p><p>嘛，虽然这次我似乎奇迹般地解开了误会，但一人反省会的内容基本上是无法挽回的。认为被误会这件事，可能本身就是一种误会，或者对方可能根本不在意。故意找借口只会更加尴尬。因此，当事人会陷入不可磨灭的羞耻漩涡之中。</p><p>解决办法只有快点睡觉……。不要再看这种文章了，你也去睡觉吧。想要从深夜特有的「魔力」之中逃离，除了睡眠之外别无他法……。</p><hr><p><img src="https://img.tree-novel.com/talk/45224fc56fa2f7b1698d27abe01cadea.png" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/d5fd0d93e3226583d580a473114b141e.JPG" alt="" loading="lazy"></p><blockquote><p>本周的にゃるら的物品：</p><p>【PRI☆CHAN的毛绒玩具】装在本来应该是鞋柜的地方里的PRI☆CHAN毛绒玩具。最上面的戴雅酱的毛绒玩具，因其独特的可爱而在部分宅男中引起了热烈反响，甚至一度走高到几十万日元的价格，但由于官方恰好再贩了这款玩具，所以事情平息了下来。</p></blockquote>',13);function b(g,N){const n=a("ExternalLinkIcon"),l=a("RouterLink");return p(),s("div",null,[_(" more "),f,e("p",null,[t("原文链接："),e("a",h,[t("第4回／深夜の一人反省会"),o(n)])]),e("blockquote",null,[u,e("p",null,[o(l,{to:"/posts/Translate/nyalra_kb_03.html"},{default:i(()=>[t("【奈亚拉面壁自语】第03回｜孤独的好处【221206】")]),_:1})])]),k])}const y=c(m,[["render",b],["__file","nyalra_kb_04.html.vue"]]);export{y as default};
